        "\n",
        "print(\"\\n\" + \"─\" * 60)\n",
        "print(\"SECTION 2 – FEATURE IMPORTANCE ANALYSIS (Random Forest)\")\n",
        "print(\"─\" * 60)\n",
        "\n",
        "rf_clf      = models[\"RandomForest\"].steps[-1][1]\n",
        "importances = rf_clf.feature_importances_\n",
        "\n",
        "if feat_names is None:\n",
