        "\n",
        "fi_df = pd.DataFrame({\n",
        "    \"Feature\":    used_names,\n",
        "    \"Importance\": importances\n",
        "}).sort_values(\"Importance\", ascending=False).reset_index(drop=True)\n",
        "\n",
        "# ── categorise features ──\n",
        "def categorise(f):\n",
        "    f = f.lower()\n",
        "    if \"mfcc\" in f:\n",
        "        return \"MFCC\"\n",
        "    elif f.startswith(\"f1\") or f.startswith(\"f2\") or f.startswith(\"f3\"):\n",
        "        return \"Formants\"\n",
        "    elif \"spectral\" in f:\n",
        "        return \"Spectral\"\n",
        "    elif \"pitch\" in f:\n",
        "        return \"Pitch\"\n",
        "    elif \"zcr\" in f:\n",
        "        return \"ZCR\"\n",
        "    elif \"energy\" in f:\n",
        "        return \"Energy\"\n",
        "    elif \"vowel\" in f:\n",
        "        return \"Vowel Ratio\"\n",
        "    elif \"duration\" in f:\n",
        "        return \"Duration\"\n",
        "    else:\n",
        "        return \"Other\"\n",
        "\n",
        "fi_df[\"Category\"] = fi_df[\"Feature\"].apply(categorise)\n",
        "\n",
        "print(f\"\\nTop 20 most important features:\\n\")\n",
        "print(fi_df.head(20).to_string(index=False))\n",
