        "    \"Pitch\":       \"#A865B5\",\n",
        "    \"ZCR\":         \"#EE8833\",\n",
        "    \"Energy\":      \"#77BEDB\",\n",
        "    \"Vowel Ratio\": \"#D63B78\",\n",
        "    \"Duration\":    \"#8B8B00\",\n",
        "    \"Other\":       \"#AAAAAA\",\n",
        "}\n",
        "\n",
        "top30   = fi_df.head(TOP_N)\n",
