        "    coef_df = pd.DataFrame(coef.T,\n",
        "                           index=used_names,\n",
        "                           columns=[CLASS_NAMES[i] for i in lr_clf.classes_])\n",
        "    top_lr_feats = coef_df.mean(axis=1).nlargest(25).index\n",
        "\n",
        "    fig_lr, ax_lr = plt.subplots(figsize=(10, 7))\n",
        "    sns.heatmap(coef_df.loc[top_lr_feats],\n",
        "                ax=ax_lr,\n",
