        "                linewidths=0.4,\n",
        "                annot=False,\n",
        "                cbar_kws={\"label\": \"|Coefficient|\"})\n",
        "    ax_lr.set_title(\"Logistic Regression: |Coefficients| for Top-25 Features\",\n",
        "                    fontweight=\"bold\")\n",
        "    ax_lr.set_xticklabels(ax_lr.get_xticklabels(), rotation=30, ha=\"right\")\n",
